using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search functionality for the research agent.
/// In production, replace the simulated results with a real search API (e.g., Bing Search).
/// </summary>
public sealed class WebSearchTool
{
    private static readonly Dictionary<string, string[]> SimulatedResults = new(StringComparer.OrdinalIgnoreCase)
    {
        ["quantum computing"] =
        [
            "Quantum computing uses qubits that can exist in superposition, enabling parallel computation. IBM and Google have demonstrated quantum supremacy with processors exceeding 1000 qubits.",
            "Applications include cryptography, drug discovery, optimization problems, and materials science. Quantum error correction remains a major challenge.",
            "The quantum computing market is projected to reach $65 billion by 2030. Key players include IBM, Google, Microsoft, and IonQ."
        ],
        ["artificial intelligence"] =
        [
            "Large language models like GPT-4 and Claude have demonstrated emergent reasoning capabilities. Training costs exceed $100M for frontier models.",
            "AI regulation is advancing globally: the EU AI Act classifies systems by risk level. The US has issued executive orders on AI safety.",
            "Agentic AI systems that can use tools and plan multi-step tasks are the latest frontier, with applications in software engineering and research."
        ],
        ["climate change"] =
        [
            "Global temperatures have risen 1.1°C above pre-industrial levels. The Paris Agreement targets limiting warming to 1.5°C.",
            "Renewable energy capacity grew 50% in 2023, led by solar installations. Battery storage costs fell below $100/kWh.",
            "Carbon capture technologies are scaling up, with direct air capture plants operational in Iceland and the US."
        ]
    };

    [Description("Searches the web for information on a given query. Returns a list of relevant search result snippets.")]
    public static string[] SearchWeb(
        [Description("The search query to look up on the web")] string query)
    {
        Console.WriteLine($"  🔍 Searching web for: \"{query}\"");

        // Try exact match first, then partial match
        if (SimulatedResults.TryGetValue(query, out var results))
        {
            return results;
        }

        var partialMatch = SimulatedResults.Keys
            .FirstOrDefault(k => query.Contains(k, StringComparison.OrdinalIgnoreCase)
                              || k.Contains(query, StringComparison.OrdinalIgnoreCase));

        if (partialMatch is not null)
        {
            return SimulatedResults[partialMatch];
        }

        return [$"Search results for '{query}': This is a simulated search result. In production, integrate with a real search API like Bing Search or Google Custom Search."];
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking functionality for the research agent to record findings.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<Note> _notes = [];

    public IReadOnlyList<Note> Notes => _notes;

    [Description("Saves a research note with a title and content. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The detailed content of the note")] string content)
    {
        var note = new Note(title, content, DateTime.UtcNow);
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note '{title}' saved successfully. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieves all previously saved research notes.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var formatted = _notes.Select((n, i) =>
            $"[{i + 1}] {n.Title} ({n.Timestamp:u})\n    {n.Content}");

        return string.Join("\n\n", formatted);
    }
}

public sealed record Note(string Title, string Content, DateTime Timestamp);

