using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using ResearchAgent.Tools;

var builder = Host.CreateApplicationBuilder(args);

// Register the OpenAI-backed chat client via MEAI abstraction.
// API key is loaded from environment or configuration — never hardcoded.
var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the AI:ApiKey configuration value or OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(chatClientBuilder => chatClientBuilder
    .UseOpenAIChatClient(modelId, apiKey));

builder.Services.AddSingleton<NoteTakingTool>();

using var host = builder.Build();

// Resolve services
var chatClient = host.Services.GetRequiredService<IChatClient>();
var noteTaking = host.Services.GetRequiredService<NoteTakingTool>();

// Define tools with explicit schemas via AIFunctionFactory
var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearchTool.SearchWeb),
    AIFunctionFactory.Create(noteTaking.SaveNote),
    AIFunctionFactory.Create(noteTaking.GetAllNotes),
};

// Create the research agent with Microsoft Agent Framework
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. Your goal is to thoroughly research a given topic using web search,
        take organized notes on your findings, and then provide a comprehensive summary.

        Follow this workflow:
        1. Search the web for information on the topic (try multiple related queries)
        2. Save important findings as notes with descriptive titles
        3. Review your notes and provide a well-structured summary

        Always cite what you found in your searches. Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "An AI agent that researches topics using web search and note-taking tools",
    tools: tools);

// Determine the research topic
var topic = args.Length > 0
    ? string.Join(' ', args)
    : "quantum computing";

Console.WriteLine($"🔬 Research Agent - Investigating: \"{topic}\"");
Console.WriteLine(new string('─', 50));

// Run the agent with guardrails
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

var response = await agent.RunAsync(
    $"Please research the following topic thoroughly and provide a summary: {topic}",
    options: runOptions);

Console.WriteLine();
Console.WriteLine(new string('─', 50));
Console.WriteLine("📋 RESEARCH SUMMARY");
Console.WriteLine(new string('─', 50));
Console.WriteLine(response.Text);

// Display collected notes
if (noteTaking.Notes.Count > 0)
{
    Console.WriteLine();
    Console.WriteLine(new string('─', 50));
    Console.WriteLine($"📓 NOTES COLLECTED ({noteTaking.Notes.Count})");
    Console.WriteLine(new string('─', 50));
    foreach (var note in noteTaking.Notes)
    {
        Console.WriteLine($"  • {note.Title}");
        Console.WriteLine($"    {note.Content}");
        Console.WriteLine();
    }
}

